export const TOPICS_D = [
  // ── TK–2 ───────────────────────────────────────────────────────────────────
  { id:'sorting-classifying', title:'Sorting and Classifying', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['sort','classify','attribute','category','group'], summary:'Sort objects by color, shape, size, or other attributes.', intro:'Sorting groups objects by a shared property. One object can belong to multiple groups.', steps:[{title:'Choose an attribute',body:'Color: red, blue, green. Shape: circle, square. Size: big, small.'},{title:'Form groups',body:'Put all red objects together, all blue together.'},{title:'Re-sort by different attribute',body:'Now sort the same objects by shape instead.'},{title:'Venn diagrams',body:'Show objects belonging to two groups at once with overlapping circles.'}], explanation:'Sorting and classifying is the foundation of set theory and database organization.', exercises:[{question:'Sort 3 circles and 4 squares by shape. Groups?',answer:'Circles: 3. Squares: 4.',hint:'Shape is the attribute.'},{question:'Objects can be sorted by __ OR __ at the same time.',answer:'Two attributes simultaneously (Venn diagram)',hint:'Intersection of two properties.'},{question:'4 red circles, 3 blue circles, 2 red squares. Sort by color: red group?',answer:'6 (4+2)',hint:'Red circles + red squares.'}]},
  { id:'basic-addition-regrouping', title:'Three-Digit Addition', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['three digit addition','hundreds','regrouping'], summary:'Add three-digit numbers with and without regrouping.', intro:'Three-digit addition extends two-digit methods to include the hundreds column.', steps:[{title:'Align by place',body:'Write numbers vertically, lining up ones, tens, hundreds.'},{title:'Add ones',body:'If sum≥10, write ones digit, carry the ten.'},{title:'Add tens',body:'Include carried 1. If sum≥10, carry to hundreds.'},{title:'Add hundreds',body:'Include carried 1.'}], explanation:'Each column is a independent addition in a specific place — regrouping moves value leftward.', exercises:[{question:'347+285=?',answer:'632',hint:'Ones: 12, carry 1. Tens: 13, carry 1. Hundreds: 6.'},{question:'509+374=?',answer:'883',hint:'Ones: 13. Tens: 8. Hundreds: 8.'},{question:'456+544=?',answer:'1000',hint:'Every column regroups!'}]},
  { id:'three-digit-subtraction', title:'Three-Digit Subtraction', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['three digit subtraction','borrow','hundreds'], summary:'Subtract three-digit numbers using regrouping across places.', intro:'Sometimes you need to borrow not just from tens but from hundreds too.', steps:[{title:'Subtract ones',body:'If top < bottom, borrow from tens. If tens=0, borrow from hundreds first.'},{title:'Chain borrowing',body:'503-268: ones: need to borrow, but tens=0. Borrow from hundreds: 10 tens, borrow 1: 13-8=5. Tens: 9-6=3. Hundreds: 4-2=2. Answer 235.'},{title:'Check',body:'235+268=503 ✓'}], explanation:'Chain borrowing across zeros is the hardest regrouping case — always check by adding back.', exercises:[{question:'700-354=?',answer:'346',hint:'700=699+1 trick or chain borrow.'},{question:'605-289=?',answer:'316',hint:'Borrow from 6 hundreds.'},{question:'832-497=?',answer:'335',hint:'Borrow from tens, then hundreds.'}]},
  { id:'equal-groups', title:'Equal Groups and Sharing', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['equal groups','fair share','division intro','distribute'], summary:'Divide objects into equal groups to introduce the concept of division.', intro:'Fair sharing means each person gets the same amount — no extras.', steps:[{title:'Count total',body:'12 apples to share among 4 friends.'},{title:'Deal out one at a time',body:'Give one to each friend repeatedly until gone.'},{title:'Count each share',body:'Each friend has 3 apples.'},{title:'Connection to division',body:'12 ÷ 4 = 3.'}], explanation:'Equal sharing lays the foundation for division, fractions, and proportional reasoning.', exercises:[{question:'15 crayons shared among 3. Each gets?',answer:'5',hint:'15÷3=5.'},{question:'20 stickers into groups of 4. How many groups?',answer:'5',hint:'20÷4=5.'},{question:'8 cookies split 2 ways. Each gets?',answer:'4',hint:'8÷2=4.'}]},
  { id:'before-after-between', title:'Before, After, and Between Numbers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['before after between','sequence','number order'], summary:'Name numbers that come before, after, or between given numbers.', intro:'"Before" means one less. "After" means one more. "Between" is in the middle.', steps:[{title:'Before',body:'Number before 47 = 46. One less.'},{title:'After',body:'Number after 99 = 100. One more.'},{title:'Between',body:'Between 35 and 37: 36.'},{title:'Multiple betweens',body:'Between 20 and 25: 21,22,23,24.'}], explanation:'This skill builds number sequence fluency and prepares children for the number line.', exercises:[{question:'Number before 100?',answer:'99',hint:'One less than 100.'},{question:'Between 58 and 62?',answer:'59,60,61',hint:'Three numbers in between.'},{question:'Number after 249?',answer:'250',hint:'One more.'}]},
  { id:'2d-patterns', title:'Repeating Patterns', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['patterns','repeating','AB','AABB','predict'], summary:'Identify, extend, and create repeating patterns.', intro:'A repeating pattern has a core (smallest repeating unit) that repeats over and over.', steps:[{title:'Find the core',body:'red-blue-red-blue: core = red-blue (AB pattern).'},{title:'Name the pattern',body:'AB, AAB, AABB, ABC, etc.'},{title:'Extend',body:'Identify the core and continue it.'},{title:'Predict',body:'"What comes 10th?" Find 10th position in the repeating core.'}], explanation:'Repeating patterns are found in music, art, textiles, and the seasons.', exercises:[{question:'Circle, square, circle, square, ___',answer:'Circle',hint:'AB pattern repeats.'},{question:'1,2,2,1,2,2,___',answer:'1',hint:'Core=1,2,2.'},{question:'5th position in A,B,C,A,B,C,…?',answer:'B',hint:'5=3+2, so 2nd in core=B.'}]},
  { id:'temperature-reading', title:'Reading Thermometers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['temperature','thermometer','Celsius','Fahrenheit','degree'], summary:'Read temperatures on Celsius and Fahrenheit thermometers.', intro:'A thermometer measures how hot or cold something is in degrees.', steps:[{title:'Read the scale',body:'Find the top of the mercury/color column. Read the nearest degree.'},{title:'Celsius vs Fahrenheit',body:'Water freezes at 0°C/32°F. Water boils at 100°C/212°F.'},{title:'Positive vs negative',body:'Below 0°C is freezing cold.'},{title:'Compare temperatures',body:'30°C is hot summer. 10°C is cool. 0°C is freezing.'}], explanation:'The Celsius scale is used by scientists worldwide. Fahrenheit is used mainly in the US.', exercises:[{question:'Water freezes at _°C.',answer:'0°C',hint:'Definition of 0°C.'},{question:'Hot day: 35°C or 5°C?',answer:'35°C',hint:'Higher Celsius = warmer.'},{question:'-10°C — is it above or below freezing?',answer:'Below freezing',hint:'Negative = below 0°C.'}]},
  { id:'doubles-and-near-doubles', title:'Doubles and Near Doubles', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['doubles','near doubles','addition strategy','mental math'], summary:'Use doubles facts to quickly solve near-doubles addition.', intro:'Doubles: 6+6=12. Near doubles: 6+7=12+1=13. One more or less than a double.', steps:[{title:'Know doubles to 20',body:'1+1=2, 2+2=4,…, 9+9=18, 10+10=20.'},{title:'Near double = double ±1',body:'7+8=7+7+1=15. Or 8+8-1=15.'},{title:'Apply',body:'5+6=5+5+1=11.'},{title:'Practice',body:'Flash cards for doubles. Use for near doubles.'}], explanation:'Doubles facts are the easiest to memorize. Near doubles strategy cuts memorization in half.', exercises:[{question:'8+9=? (use near doubles)',answer:'17',hint:'8+8=16. One more=17.'},{question:'6+7=?',answer:'13',hint:'6+6+1 or 7+7-1.'},{question:'Double of 7?',answer:'14',hint:'7+7=14.'}]},
  { id:'counting-large-collections', title:'Counting Large Collections', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['counting','estimate','groups of ten','large numbers'], summary:'Count large collections efficiently by grouping into tens.', intro:'Counting one-by-one is slow. Grouping into tens is faster and more accurate.', steps:[{title:'Group into 10s',body:'Move objects into groups of 10 as you count.'},{title:'Count the tens',body:'5 groups × 10 = 50.'},{title:'Count leftover ones',body:'Add remaining: 50 + 7 = 57.'},{title:'Estimate first',body:'Estimate before counting precisely to develop number sense.'}], explanation:'Grouping by 10 is how humans manage large quantities efficiently — the origin of the base-10 system.', exercises:[{question:'4 groups of 10 plus 3. How many?',answer:'43',hint:'40+3=43.'},{question:'3 tens and 8 ones?',answer:'38',hint:'30+8=38.'},{question:'Estimate: a jar of ~50 pennies. Actual 47. Good estimate?',answer:'Yes — within a reasonable range',hint:'50 is close to 47.'}]},
  { id:'greater-than-less-than-100', title:'Comparing Numbers to 100', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['compare','greater','less','equal','two digit'], summary:'Compare two-digit numbers using place value.', intro:'Compare tens digits first. If equal, compare ones digits.', steps:[{title:'Tens first',body:'45 vs 37: tens 4>3 so 45>37.'},{title:'If tens equal, compare ones',body:'45 vs 48: tens equal (4=4). Ones: 5<8 so 45<48.'},{title:'Equal numbers',body:'45=45: identical digits in same places.'},{title:'Use symbols',body:'Write >, <, or =.'}], explanation:'Place value comparison works because tens are always worth more than ones.', exercises:[{question:'72 __ 68',answer:'>',hint:'Tens: 7>6.'},{question:'54 __ 57',answer:'<',hint:'Tens equal. Ones: 4<7.'},{question:'93 __ 93',answer:'=',hint:'Identical.'}]},

  // ── Grades 3–5 ─────────────────────────────────────────────────────────────
  { id:'fraction-equivalence-model', title:'Equivalent Fractions: Area Models', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['equivalent fractions','area model','visual','multiply divide'], summary:'Use area models to understand and find equivalent fractions.', intro:'Two fractions are equivalent if they shade the same portion of the same whole.', steps:[{title:'Draw the same size whole',body:'1/2 of a rectangle = shaded 2 out of 4 = 4 out of 8.'},{title:'Multiply numerator and denominator',body:'1/2 × 2/2 = 2/4. Same value, different notation.'},{title:'Simplify',body:'4/6 ÷ 2/2 = 2/3.'},{title:'LCD for comparison',body:'Find LCD to make denominators match before comparing.'}], explanation:'Equivalent fractions are different names for the same point on the number line.', exercises:[{question:'Find 3 fractions equivalent to 2/3.',answer:'4/6, 6/9, 8/12',hint:'Multiply by 2/2, 3/3, 4/4.'},{question:'Simplify 18/24.',answer:'3/4',hint:'GCF(18,24)=6. ÷6.'},{question:'Which denominators work for 3/4 equivalent with denominator 20?',answer:'15/20',hint:'4×5=20, so 3×5=15.'}]},
  { id:'customary-capacity-conversion', title:'Capacity Conversions', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['capacity','cups','pints','quarts','gallons','convert'], summary:'Convert between cups, pints, quarts, and gallons.', intro:'Capacity measures how much liquid a container holds.', steps:[{title:'Conversion ladder',body:'2 cups=1 pint. 2 pints=1 quart. 4 quarts=1 gallon.'},{title:'To smaller unit',body:'3 gallons = 3×4=12 quarts.'},{title:'To larger unit',body:'16 cups ÷ 2 = 8 pints ÷ 2 = 4 quarts ÷ 4 = 1 gallon.'},{title:'Visual',body:'"King Henry Died (of) Drinking Cold Milk": kilo,hecto,deca,unit,deci,centi,milli for metric.'}], explanation:'Capacity conversions appear in cooking, chemistry, and manufacturing.', exercises:[{question:'2 gallons = ? quarts',answer:'8 quarts',hint:'2×4=8.'},{question:'16 pints = ? gallons',answer:'2 gallons',hint:'16/2=8 quarts/4=2.'},{question:'6 cups = ? pints',answer:'3 pints',hint:'6/2=3.'}]},
  { id:'multiplication-by-multiples-of-10', title:'Multiply by Multiples of 10', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['multiply tens hundreds','mental math','shortcuts'], summary:'Multiply any number by 10, 100, or other multiples of ten mentally.', intro:'Multiplying by 10 appends a zero. By 100, append two zeros. Combine for multiples.', steps:[{title:'×10, ×100, ×1000',body:'43×10=430. 43×100=4300.'},{title:'Multiply by multiples',body:'43×30: think 43×3=129, then ×10=1290.'},{title:'Why it works',body:'30=3×10. Associative: (43×3)×10.'},{title:'Estimate with this',body:'47×29≈47×30=1410.'}], explanation:'This technique is the mental math application of the associative property.', exercises:[{question:'56×40=?',answer:'2240',hint:'56×4=224, ×10=2240.'},{question:'23×300=?',answer:'6900',hint:'23×3=69, ×100=6900.'},{question:'Estimate 48×52.',answer:'≈2500',hint:'50×50=2500.'}]},
  { id:'geometry-polygons-properties', title:'Properties of Polygons', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['polygon','regular','irregular','sides','vertices','interior angles'], summary:'Classify polygons and find the sum of their interior angles.', intro:'A polygon is a closed figure with straight sides. Properties depend on the number of sides.', steps:[{title:'Polygon names',body:'3=triangle, 4=quadrilateral, 5=pentagon, 6=hexagon, 7=heptagon, 8=octagon.'},{title:'Regular vs irregular',body:'Regular: all sides equal and all angles equal. Irregular: otherwise.'},{title:'Interior angle sum',body:'Sum=(n-2)×180°. Triangle: 180°. Quadrilateral: 360°. Pentagon: 540°.'},{title:'Each angle of regular polygon',body:'Each=sum/n. Regular hexagon: 720°/6=120°.'}], explanation:'The formula (n-2)×180° comes from dividing any polygon into triangles from one vertex.', exercises:[{question:'Sum of interior angles of hexagon.',answer:'720°',hint:'(6-2)×180=720.'},{question:'Each angle of regular octagon.',answer:'135°',hint:'(8-2)×180/8=135.'},{question:'Sum for nonagon (9-gon)?',answer:'1260°',hint:'(9-2)×180=1260.'}]},
  { id:'geometry-perimeter-missing-side', title:'Finding Missing Sides from Perimeter', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['perimeter','missing side','algebra','solve'], summary:'Use perimeter information to find an unknown side length.', intro:'If the perimeter and some sides are known, use subtraction or equations to find the missing side.', steps:[{title:'Write the perimeter equation',body:'P = sum of all sides.'},{title:'Substitute known values',body:'P=36, three sides 9,8,7. 36=9+8+7+x.'},{title:'Solve for x',body:'36=24+x → x=12.'},{title:'Check',body:'9+8+7+12=36 ✓'}], explanation:'Finding missing sides from perimeter is an entry-level algebra word problem.', exercises:[{question:'Rectangle P=28, length=9. Width?',answer:'5',hint:'2(9+w)=28. 9+w=14. w=5.'},{question:'Triangle P=21, sides 8 and 7. Third side?',answer:'6',hint:'21-8-7=6.'},{question:'Pentagon P=45, 4 sides each 10. 5th side?',answer:'5',hint:'45-40=5.'}]},
  { id:'statistics-mean-data-problems', title:'Mean in Problem Solving', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['mean','problem solving','find missing','data','average'], summary:'Use the mean to find a missing value or determine required values.', intro:'If you know the mean and all values but one, you can find the missing value.', steps:[{title:'Total from mean',body:'Mean=8, n=5. Total=40.'},{title:'Find missing value',body:'Four values: 6,9,7,8. Sum=30. Missing=40-30=10.'},{title:'Setting a target mean',body:'Need mean=90 across 5 tests. 4 tests: 85,88,92,91. Sum=356. Need 450-356=94 on 5th.'}], explanation:'The mean is a two-way tool: given the mean you can work backward to any missing piece.', exercises:[{question:'Mean=6, data: 5,7,4,_,8. n=5. Missing value?',answer:'6',hint:'Total=30. 5+7+4+8=24. 30-24=6.'},{question:'Need mean=80 on 4 tests. Scores 75,82,78. Need on 4th?',answer:'85',hint:'320-235=85.'},{question:'Mean of {10,15,___,11,14} = 13. Missing?',answer:'15',hint:'65-50=15.'}]},
  { id:'science-math-graphing', title:'Graphing in Science (Independent/Dependent)', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['independent variable','dependent variable','graph','x axis y axis'], summary:'Identify independent and dependent variables and place them correctly on graphs.', intro:'In an experiment, the independent variable is what you control. The dependent variable is what you measure.', steps:[{title:'Independent = x-axis',body:'What you change/control: time, temperature setting, amount of water.'},{title:'Dependent = y-axis',body:'What you measure as a result: plant height, reaction time.'},{title:'Plot and connect',body:'Plot (x,y) pairs and draw a line or curve.'},{title:'Interpret',body:'Slope shows how fast the dependent changes per unit of independent.'}], explanation:'This skill bridges math and science — all scientific graphs follow these conventions.', exercises:[{question:'Experiment: measuring plant height over 10 days. x-axis?',answer:'Days (independent)',hint:'Time is controlled.'},{question:'Temp increases, ice melts faster. Dependent?',answer:'Rate of melting',hint:'What you measure.'},{question:'Data: (1,4),(2,9),(3,16). Plot type?',answer:'Nonlinear (quadratic-looking)',hint:'Not evenly spaced y-values.'}]},
  { id:'problem-solving-strategies', title:'Problem-Solving Strategies', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['strategy','draw picture','make list','work backwards','guess check'], summary:'Apply multiple problem-solving strategies: draw, list, work backwards, guess-check.', intro:'There is no single method for all problems. Good problem solvers have a toolkit.', steps:[{title:'Draw a picture/model',body:'Visualize the problem. Bar models are very effective.'},{title:'Make an organized list',body:'List all cases systematically to count possibilities.'},{title:'Work backwards',body:'Start from the answer and reverse all operations.'},{title:'Guess and check',body:'Make an educated guess, check it, adjust.'}], explanation:'Pólya\'s 4-step method: Understand, Plan, Execute, Check.', exercises:[{question:'Work backwards: end with $25, spent $12, earned $8. Start with?',answer:'$29',hint:'25+12-8=29.'},{question:'How many ways to make change for 25¢ with only nickels and dimes?',answer:'3 ways (0d+5n, 1d+3n, 2d+1n)',hint:'List systematically.'},{question:'Find two consecutive integers that sum to 91.',answer:'45 and 46',hint:'Guess 45+46=91 ✓'}]},
  { id:'multiplication-two-by-two-digit', title:'Multiplying 2-Digit by 2-Digit Numbers', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['multiply','2 digit','partial products','area model'], summary:'Multiply two 2-digit numbers using partial products or the standard algorithm.', intro:'Break each factor into tens and ones, then use the distributive property.', steps:[{title:'Area model',body:'23×45: draw a 2×2 grid. 20×40=800. 20×5=100. 3×40=120. 3×5=15.'},{title:'Add partial products',body:'800+100+120+15=1035.'},{title:'Standard algorithm',body:'23×45: 23×5=115. 23×40=920. Add: 1035.'},{title:'Estimate to check',body:'20×45=900. 1035≈900 ✓'}], explanation:'Area model makes the distributive property visible. Standard algorithm is more compact.', exercises:[{question:'32×24=?',answer:'768',hint:'30×24+2×24=720+48.'},{question:'45×67=?',answer:'3015',hint:'45×60+45×7=2700+315.'},{question:'Estimate 38×52.',answer:'≈2000',hint:'40×50=2000.'}]},
  { id:'ratios-introduction', title:'Introduction to Ratios', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['ratio','compare','to','part to part','part to whole'], summary:'Write and interpret ratios comparing quantities.', intro:'A ratio compares two quantities. It can compare part-to-part or part-to-whole.', steps:[{title:'Write a ratio',body:'3 cats and 5 dogs: cats to dogs = 3:5 = 3/5 = "3 to 5."'},{title:'Part to whole',body:'3 cats out of 8 animals: 3:8.'},{title:'Equivalent ratios',body:'3:5 = 6:10. Multiply both by same number.'},{title:'Use ratios in context',body:'"2 cups of mix per 3 cups of water." Ratio 2:3.'}], explanation:'Ratios are the foundation of proportional reasoning and trigonometry.', exercises:[{question:'8 boys and 7 girls. Boys to girls ratio?',answer:'8:7',hint:'First quantity : second quantity.'},{question:'Ratio 3:4, equivalent with second term 12?',answer:'9:12',hint:'×3.'},{question:'Class has 30 students, 12 girls. Ratio girls to total?',answer:'12:30 = 2:5',hint:'Simplify by dividing by 6.'}]},
  { id:'estimation-rounding', title:'Estimation with Rounding', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['estimate','round','approximate','reasonable'], summary:'Use rounding to make quick estimates for calculations.', intro:'Estimation gives an approximate answer quickly. Always ask: "Is the exact answer reasonable?"', steps:[{title:'Round to leading digit',body:'Round to the nearest large place for fastest estimate.'},{title:'Front-end estimation',body:'348+276: add front digits 300+200=500, then adjust.'},{title:'Clustering',body:'Three numbers all near 50: 3×50=150 estimate.'},{title:'Compare to estimate',body:'Exact answer should be close to estimate. If not, recheck.'}], explanation:'Professional engineers always estimate before calculating — it catches errors.', exercises:[{question:'Estimate 489+312.',answer:'≈800',hint:'490+310=800.'},{question:'Estimate 71×8.',answer:'≈560',hint:'70×8=560.'},{question:'Exact: 3,482+2,315. Estimate first.',answer:'≈5800. Exact=5797.',hint:'3500+2300=5800.'}]},
  { id:'long-division-four-digit', title:'Long Division with 4-Digit Dividends', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['long division','4 digit','DMSB','algorithm'], summary:'Extend long division to 4-digit dividends.', intro:'The DMSB algorithm (Divide, Multiply, Subtract, Bring Down) extends to any length.', steps:[{title:'Set up',body:'2436 ÷ 4.'},{title:'Divide from left',body:'24÷4=6. Write 6. 6×4=24. 24-24=0.'},{title:'Bring down',body:'Bring 3: 03. 3÷4=0. Write 0. 0×4=0. 3-0=3.'},{title:'Bring down again',body:'Bring 6: 36. 36÷4=9. 9×4=36. 36-36=0. Answer: 609.'}], explanation:'Every "bring down" starts a new mini-division problem.', exercises:[{question:'3648÷6=?',answer:'608',hint:'36÷6=6. 4÷6=0 R4. 48÷6=8.'},{question:'4825÷5=?',answer:'965',hint:'48÷5=9R3. 32÷5=6R2. 25÷5=5.'},{question:'7203÷3=?',answer:'2401',hint:'7÷3=2R1. 12÷3=4. 00÷3=0. 3÷3=1.'}]},
  { id:'geometry-regular-polygons', title:'Regular Polygons and Tessellations', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['regular polygon','tessellation','tile','angle','fit'], summary:'Identify which regular polygons can tessellate and explain why.', intro:'A tessellation fills a plane with no gaps or overlaps. Regular polygons tessellate if their angle divides 360°.', steps:[{title:'Regular tessellators',body:'Equilateral triangle (60°), square (90°), regular hexagon (120°). All divide 360° evenly.'},{title:'Why hexagon?',body:'6 hexagons meet at a point: 6×120°=720°… Wait, 360°/120°=3. So 3 hexagons meet at each vertex.'},{title:'Combination tessellations',body:'Mixing polygons: 3-3-3-3-6 pattern, etc.'},{title:'Real examples',body:'Honeybees use hexagons — most efficient packing.'}], explanation:'Interior angle must divide 360° evenly for regular tessellation.', exercises:[{question:'Why can\'t regular pentagons tessellate?',answer:'Interior angle 108°. 360/108 is not an integer.',hint:'360÷108≈3.33.'},{question:'How many equilateral triangles meet at each vertex?',answer:'6',hint:'360÷60=6.'},{question:'Name the 3 regular tessellating polygons.',answer:'Triangle, square, hexagon',hint:'Angles 60°, 90°, 120° divide 360°.'}]},
  { id:'converting-mixed-decimal', title:'Fractions, Decimals, and Percents', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fractions decimals percents','convert','equivalence'], summary:'Convert fluently between fractions, decimals, and percents.', intro:'Fractions, decimals, and percents are three representations of the same value.', steps:[{title:'Fraction to decimal',body:'Divide numerator by denominator. 3/4=0.75.'},{title:'Decimal to percent',body:'Multiply by 100. 0.75=75%.'},{title:'Percent to fraction',body:'Over 100 and simplify. 75%=75/100=3/4.'},{title:'Benchmark conversions',body:'1/4=0.25=25%. 1/3≈0.333=33.3%. 1/2=0.5=50%.'}], explanation:'Fluency across representations is essential for financial literacy and data interpretation.', exercises:[{question:'Convert 2/5 to decimal and percent.',answer:'0.4 and 40%',hint:'2÷5=0.4. 0.4×100=40.'},{question:'Convert 85% to fraction.',answer:'17/20',hint:'85/100=17/20.'},{question:'Order: 0.6, 55%, 3/5.',answer:'All equal 0.6',hint:'55%=0.55≠0.6. But 3/5=0.6=60%.'}]},
  { id:'area-irregular-polygons', title:'Area of Irregular Polygons', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['area','irregular','count squares','estimate'], summary:'Find the area of irregular shapes by counting unit squares or decomposing.', intro:'Irregular shapes can be measured by counting grid squares or breaking into rectangles.', steps:[{title:'Count complete squares',body:'Count all unit squares completely inside the shape.'},{title:'Half squares',body:'Count partial squares. Group pairs into 1 unit.'},{title:'Decompose',body:'Split the shape into rectangles or triangles. Add areas.'},{title:'Estimation',body:'For curved shapes: count squares and estimate halves.'}], explanation:'This approach introduces the concept of integration — adding up infinitely thin strips to find area.', exercises:[{question:'Shape covers 7 full squares and 4 half squares on grid. Area?',answer:'9 square units',hint:'7+4(½)=7+2=9.'},{question:'L-shape: 5×4 with 2×2 cut. Area?',answer:'16',hint:'20-4=16.'},{question:'Cross shape: 3×7 + 3×3 (no double count)',answer:'21+9-0=30 — check for overlap',hint:'Depends on arrangement.'}]},
  { id:'time-word-problems', title:'Time Word Problems', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['time','elapsed','schedule','start end','calendar'], summary:'Solve time problems involving elapsed time and scheduling.', intro:'Time word problems require understanding elapsed time, schedules, and conversions.', steps:[{title:'Start time + elapsed = end time',body:'Start 9:15, elapsed 2h45m: 9:15+2:45=12:00.'},{title:'End - start = elapsed',body:'End 3:30, start 1:15: 3:30-1:15=2:15 elapsed.'},{title:'Adding time',body:'2h35m + 1h40m: minutes 35+40=75=1h15m. Hours 2+1+1=4. Total: 4h15m.'},{title:'Calendar problems',body:'Add/subtract days using month lengths.'}], explanation:'Time arithmetic uses 60-minute hours, not base-10 — requiring special care.', exercises:[{question:'Start 11:45 AM, elapsed 3h30m. End time?',answer:'3:15 PM',hint:'11:45+3:30=15:15=3:15PM.'},{question:'Flight departs 7:50 AM, arrives 1:20 PM. Duration?',answer:'5h 30m',hint:'7:50→1:20.'},{question:'2h45m + 3h30m = ?',answer:'6h 15m',hint:'75min=1h15m. 2+3+1=6h.'}]},
  { id:'greatest-common-factor', title:'Greatest Common Factor (GCF)', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['GCF','greatest common factor','simplify fractions'], summary:'Find the GCF of two numbers to simplify fractions and solve problems.', intro:'The GCF is the largest number that divides both numbers evenly.', steps:[{title:'List factors',body:'Factors of 18: 1,2,3,6,9,18. Factors of 24: 1,2,3,4,6,8,12,24.'},{title:'Find common factors',body:'Common: 1,2,3,6.'},{title:'GCF = largest',body:'GCF=6.'},{title:'Use to simplify',body:'18/24 ÷ 6/6 = 3/4.'}], explanation:'GCF is also found using prime factorization — product of shared prime factors.', exercises:[{question:'GCF of 12 and 16.',answer:'4',hint:'Common factors: 1,2,4.'},{question:'Simplify 20/28 using GCF.',answer:'5/7',hint:'GCF=4. 20÷4=5, 28÷4=7.'},{question:'GCF of 15 and 25.',answer:'5',hint:'Common factors: 1,5.'}]},
  { id:'least-common-multiple', title:'Least Common Multiple (LCM)', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['LCM','least common multiple','common denominator'], summary:'Find the LCM of two numbers for use in fraction operations and scheduling.', intro:'The LCM is the smallest number both numbers divide into evenly.', steps:[{title:'List multiples',body:'Multiples of 4: 4,8,12,16,20. Multiples of 6: 6,12,18,24.'},{title:'Find smallest common',body:'First common: 12. LCM=12.'},{title:'Use for fractions',body:'1/4+1/6: LCD=12. 3/12+2/12=5/12.'},{title:'Via prime factorization',body:'LCM=highest power of each prime in either number.'}], explanation:'LCM gives the smallest common denominator for adding fractions.', exercises:[{question:'LCM of 8 and 12.',answer:'24',hint:'Multiples of 8: 8,16,24. Of 12: 12,24.'},{question:'1/3+1/4 using LCM.',answer:'7/12',hint:'LCM=12. 4/12+3/12.'},{question:'LCM of 5 and 7.',answer:'35',hint:'No common factors → 5×7=35.'}]},
  { id:'geometry-coordinate-grid', title:'Coordinate Grid Navigation', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['coordinate grid','x y','ordered pair','navigate','plot'], summary:'Navigate and use ordered pairs to locate points on a coordinate grid.', intro:'The coordinate grid uses two number lines to describe any location uniquely.', steps:[{title:'Axes',body:'x = horizontal (left-right). y = vertical (up-down). Origin (0,0) = intersection.'},{title:'Read ordered pairs',body:'(3,2): go right 3, up 2.'},{title:'Plot points',body:'From origin, move right x units, up y units, mark.'},{title:'Real-world application',body:'Treasure maps, GPS coordinates, chess notation (algebraically).'}], explanation:'Coordinate systems were invented by Descartes — connecting geometry to algebra.', exercises:[{question:'Plot (4,3). Which direction from origin?',answer:'Right 4, up 3',hint:'x first, then y.'},{question:'Name the point 2 right and 5 up.',answer:'(2,5)',hint:'(x,y).'},{question:'Reflection of (3,4) over x-axis.',answer:'(3,-4)',hint:'y changes sign.'}]},
  { id:'expanded-notation', title:'Expanded Notation and Word Form', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['expanded notation','word form','standard form','place value'], summary:'Write numbers in standard, expanded, and word forms.', intro:'Three forms describe the same number: standard (5,347), expanded (5000+300+40+7), and word form.', steps:[{title:'Standard to expanded',body:'4,623 = 4000+600+20+3.'},{title:'Expanded to standard',body:'7000+400+0+8 = 7,408.'},{title:'Standard to word',body:'"Four thousand, six hundred twenty-three."'},{title:'Word to standard',body:'"Two thousand forty" = 2,040.'}], explanation:'Multiple representations reinforce the meaning of each digit.', exercises:[{question:'Write 6,050 in expanded form.',answer:'6000+50',hint:'No hundreds or ones.'},{question:'Expanded: 3000+200+7. Standard form?',answer:'3,207',hint:'Fill zeros for missing places.'},{question:'Word form of 9,001.',answer:'Nine thousand one',hint:'No hundreds or tens.'}]},
  { id:'fractions-greater-than-one', title:'Fractions Greater Than One', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['improper fraction','mixed number','greater than one','convert'], summary:'Work with fractions greater than 1 as improper fractions or mixed numbers.', intro:'Fractions like 7/4 are greater than 1. They can be written as mixed numbers (1¾).', steps:[{title:'Improper fraction',body:'Numerator > denominator. 7/4.'},{title:'Convert to mixed',body:'7÷4=1R3. 1¾.'},{title:'Convert to improper',body:'2⅗: 2×5+3=13. 13/5.'},{title:'Compare',body:'5/3 or 4/3? Same denominator: 5/3 > 4/3.'}], explanation:'Both forms are mathematically equivalent — use whichever is more helpful.', exercises:[{question:'Convert 11/3 to mixed number.',answer:'3⅔',hint:'11÷3=3R2.'},{question:'Convert 4⅛ to improper fraction.',answer:'33/8',hint:'4×8+1=33.'},{question:'Order: 7/3, 8/3, 2.',answer:'7/3, 2, 8/3',hint:'6/3=2.'}]},

  // ── Grades 6–8 ─────────────────────────────────────────────────────────────
  { id:'algebraic-identities', title:'Algebraic Identities', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['algebraic identity','FOIL','perfect square','difference of squares','expand'], summary:'Recognize and apply special product identities.', intro:'Algebraic identities are patterns in polynomial multiplication that hold for all values.', steps:[{title:'(a+b)²=a²+2ab+b²',body:'(x+3)²=x²+6x+9.'},{title:'(a-b)²=a²-2ab+b²',body:'(x-4)²=x²-8x+16.'},{title:'(a+b)(a-b)=a²-b²',body:'(x+5)(x-5)=x²-25.'},{title:'Use in reverse',body:'Factor x²-16=(x+4)(x-4).'}], explanation:'These identities reduce calculation time and are used in factoring, calculus, and number theory.', exercises:[{question:'(x+7)²=?',answer:'x²+14x+49',hint:'a=x, b=7.'},{question:'(2x-3)²=?',answer:'4x²-12x+9',hint:'a=2x, b=3.'},{question:'(x+9)(x-9)=?',answer:'x²-81',hint:'Difference of squares.'}]},
  { id:'multi-step-equation-applications', title:'Multi-Step Equations in Real Life', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['equation','multi-step','application','real world'], summary:'Set up and solve multi-step equations from real-world scenarios.', intro:'Real problems often need two or more steps. The key is translating correctly.', steps:[{title:'Define variable',body:'Let x = unknown.'},{title:'Translate to equation',body:'"4 less than 3 times a number is 11": 3x-4=11.'},{title:'Solve',body:'3x=15. x=5.'},{title:'Verify in context',body:'"Three times 5 is 15. Four less than 15 is 11." ✓'}], explanation:'Translation accuracy is more important than solving technique.', exercises:[{question:'"Total cost is $47: bought items at $9 each plus a $2 fee." How many items?',answer:'5 items',hint:'9n+2=47. 9n=45. n=5.'},{question:'"Twice a number plus 6 equals 18." Number?',answer:'6',hint:'2n+6=18. n=6.'},{question:'Three consecutive integers sum to 51. Find them.',answer:'16,17,18',hint:'n+(n+1)+(n+2)=51.'}]},
  { id:'circumference-real-world', title:'Circumference in Real-World Problems', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['circumference','circle','real world','wheel','distance'], summary:'Apply circumference to real-world contexts like wheel rotations and fencing.', intro:'Circumference = total distance around a circle. One rotation of a wheel travels one circumference.', steps:[{title:'Formula',body:'C=πd=2πr.'},{title:'Wheel problem',body:'Wheel diameter=60cm. Rotations to travel 1km: 1000m÷(0.6π)≈530 rotations.'},{title:'Fencing a circular garden',body:'r=5m. Fencing needed=2π(5)=10π≈31.4m.'},{title:'Arc length',body:'Partial circles: arc=(θ/360°)×C.'}], explanation:'Odometers measure distance by counting tire rotations × circumference.', exercises:[{question:'Bicycle tire diameter 70cm. Rotations to travel 110m?',answer:'≈50',hint:'C=70πcm≈220cm. 11000/220=50.'},{question:'Fencing circular pond r=7m.',answer:'≈44m',hint:'2π×7≈44.'},{question:'Arc length: r=12, θ=60°.',answer:'4π≈12.6',hint:'(60/360)×24π=4π.'}]},
  { id:'probability-geometric', title:'Geometric Probability', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['geometric probability','area','favorable region','total area'], summary:'Calculate probability using area ratios.', intro:'Geometric probability = favorable area / total area. Useful when outcomes correspond to regions.', steps:[{title:'Define regions',body:'Dart thrown randomly at a 10×10 board with a 3×3 bullseye.'},{title:'Calculate areas',body:'Total=100. Favorable=9.'},{title:'Probability',body:'P(bullseye)=9/100=9%.'}], explanation:'Geometric probability extends discrete probability to continuous, spatial situations.', exercises:[{question:'Square 8×8 with circle r=3 inside. P(landing in circle)?',answer:'9π/64≈0.44',hint:'Circle area=9π. Square=64.'},{question:'Target: circle r=5 inside square side 10. P?',answer:'π/4≈0.785',hint:'25π/100=π/4.'},{question:'Random point in 4×6 rectangle. P(x<2)?',answer:'2/4=1/2 or less depending on x<2 strip',hint:'Strip 2×6=12. Total=24. P=1/2.'}]},
  { id:'mean-absolute-deviation', title:'Mean Absolute Deviation (MAD)', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['MAD','mean absolute deviation','spread','variability'], summary:'Calculate MAD to measure the average spread of data from the mean.', intro:'MAD measures average distance of data points from the mean — a simple spread measure.', steps:[{title:'Find the mean',body:'Data: {3,7,5,9,1}. Mean=5.'},{title:'Find each |deviation|',body:'|3-5|=2, |7-5|=2, |5-5|=0, |9-5|=4, |1-5|=4.'},{title:'Average the deviations',body:'(2+2+0+4+4)/5=12/5=2.4.'},{title:'Interpret',body:'On average, each value is 2.4 units from the mean.'}], explanation:'MAD is the mean absolute deviation — a precursor to standard deviation that uses absolute value instead of squaring.', exercises:[{question:'Data: {2,4,6,8,10}. Mean=6. MAD?',answer:'2.4',hint:'Deviations: 4,2,0,2,4. Sum=12. 12/5=2.4.'},{question:'All data equal the mean. MAD?',answer:'0',hint:'No deviation.'},{question:'Higher MAD means?',answer:'More spread out data',hint:'Greater average distance from mean.'}]},
  { id:'pythagorean-theorem-3d', title:'Pythagorean Theorem in 3D', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['Pythagorean','3D','diagonal','box','space diagonal'], summary:'Apply the Pythagorean theorem twice to find space diagonals in 3D figures.', intro:'The space diagonal of a rectangular box uses the theorem twice.', steps:[{title:'Find base diagonal first',body:'Box l=3, w=4, h=5. Base diagonal d₁=√(3²+4²)=5.'},{title:'Apply again for space diagonal',body:'d=√(d₁²+h²)=√(25+25)=√50=5√2.'},{title:'Formula shortcut',body:'d=√(l²+w²+h²).'}], explanation:'The 3D distance formula is Pythagorean theorem in three dimensions.', exercises:[{question:'Box 2×2×2. Space diagonal?',answer:'2√3',hint:'√(4+4+4)=√12=2√3.'},{question:'Box 3×4×12. Space diagonal?',answer:'13',hint:'√(9+16+144)=√169=13.'},{question:'Space diagonal 13, l=3, w=4. h?',answer:'12',hint:'3²+4²+h²=169. h=12.'}]},
  { id:'inequalities-compound', title:'Compound Inequalities', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['compound inequality','and','or','between','number line'], summary:'Solve and graph compound inequalities joined by AND or OR.', intro:'Compound inequalities combine two inequalities. AND = intersection. OR = union.', steps:[{title:'AND (between)',body:'-1<x<5: x is between -1 and 5 (both must be true).'},{title:'Solve AND',body:'2<x+3<8 → -1<x<5.'},{title:'OR (outside)',body:'x<-2 or x>4: outside both values.'},{title:'Solve OR',body:'Solve each separately. Combine.'}], explanation:'AND compound inequalities look like segments. OR look like two rays.', exercises:[{question:'Solve: -3<2x+1<7',answer:'-2<x<3',hint:'Subtract 1: -4<2x<6. Divide: -2<x<3.'},{question:'Solve: x-2<0 or x+1>5',answer:'x<2 or x>4',hint:'Two separate inequalities.'},{question:'Graph: -1≤x≤3. Open or closed circles?',answer:'Closed circles at -1 and 3',hint:'≤ means closed.'}]},
  { id:'direct-inverse-variation', title:'Direct and Inverse Variation', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['direct variation','inverse variation','constant','k','proportional'], summary:'Identify and apply direct (y=kx) and inverse (y=k/x) variation relationships.', intro:'Direct: as x increases, y increases. Inverse: as x increases, y decreases proportionally.', steps:[{title:'Direct variation',body:'y=kx. k=y/x (constant). Double x → double y.'},{title:'Inverse variation',body:'y=k/x. k=xy (constant). Double x → halve y.'},{title:'Find k from a point',body:'Direct: (4,12): k=12/4=3. Equation: y=3x.'},{title:'Inverse example',body:'(2,6): k=12. y=12/x. At x=3: y=4.'}], explanation:'Ohm\'s Law (V=IR) is direct. Pressure-volume (PV=k, Boyle\'s Law) is inverse.', exercises:[{question:'y=kx and (5,20). Find y when x=8.',answer:'32',hint:'k=4. y=4×8=32.'},{question:'Inverse: xy=24. y when x=6?',answer:'4',hint:'6y=24.'},{question:'Is y=3x direct or inverse?',answer:'Direct',hint:'y=kx form.'}]},
  { id:'scatter-plot-trend-line', title:'Drawing Trend Lines', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['trend line','line of best fit','scatter plot','slope','predict'], summary:'Draw and use trend lines on scatter plots to make predictions.', intro:'A trend line (line of best fit) passes through the middle of the scatter plot data.', steps:[{title:'Draw trend line',body:'Sketch a line with equal numbers of points above and below. Goes through the "center" of the data.'},{title:'Find slope and intercept',body:'Pick two points on the line (not data points). Calculate slope: (y₂-y₁)/(x₂-x₁).'},{title:'Equation',body:'y=mx+b.'},{title:'Predict',body:'Plug x value into equation.'}], explanation:'This is informal regression — the formal method (least squares) minimizes sum of squared residuals.', exercises:[{question:'Trend line passes (0,5) and (10,15). Equation?',answer:'y=x+5',hint:'m=(15-5)/10=1. b=5.'},{question:'Equation y=2x+3. Predict y when x=7.',answer:'17',hint:'2(7)+3=17.'},{question:'Extrapolation: predict beyond data range. Risk?',answer:'Less reliable — model may not apply outside data range',hint:'Predictions far from data are uncertain.'}]},
  { id:'statistics-mad-comparison', title:'Comparing Data Sets with MAD', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['MAD','compare','consistency','spread'], summary:'Use MAD to compare the consistency (spread) of two data sets.', intro:'When comparing two groups, mean tells us center, MAD tells us consistency.', steps:[{title:'Calculate MAD for each group',body:'Group A: MAD=2. Group B: MAD=5.'},{title:'Interpret',body:'Group A is more consistent (less spread). Group B is more variable.'},{title:'Overlap',body:'If means are close but MADs large, distributions likely overlap significantly.'},{title:'Context',body:'"Manufacturer A\'s screws have smaller MAD" = more consistent = better quality.'}], explanation:'Consistency (low spread) is as important as performance (center) in many real applications.', exercises:[{question:'A: mean=50, MAD=3. B: mean=50, MAD=8. More consistent?',answer:'A',hint:'Lower MAD = more consistent.'},{question:'A: mean=60, MAD=2. B: mean=55, MAD=8. Which group might score higher?',answer:'A — higher mean AND more consistent',hint:'Better center AND spread.'},{question:'MAD=0 means?',answer:'All data values are equal',hint:'No deviation from mean.'}]},

  // ── Grades 9–12 ────────────────────────────────────────────────────────────
  { id:'polynomial-theorems', title:'Factor and Remainder Theorems', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['factor theorem','remainder theorem','polynomial','root','zero'], summary:'Apply the Factor and Remainder Theorems to analyze polynomials.', intro:'Remainder Theorem: f(c) = remainder when f(x) is divided by (x-c). Factor Theorem: f(c)=0 ↔ (x-c) is a factor.', steps:[{title:'Remainder Theorem',body:'f(x)÷(x-2): remainder = f(2). If f(2)=7, remainder=7.'},{title:'Factor Theorem',body:'f(3)=0 → (x-3) is a factor of f(x).'},{title:'Finding zeros',body:'Test integer factors of constant term as possible rational zeros.'},{title:'Factor fully',body:'Once one factor found by theorem, divide to find others.'}], explanation:'These theorems make polynomial factoring systematic.', exercises:[{question:'f(x)=x³-2x²+x-2. Is (x-2) a factor?',answer:'f(2)=8-8+2-2=0. Yes!',hint:'Evaluate f(2).'},{question:'f(x)=x²+5x+6. f(-2)=?',answer:'0 (so x=-2 is a root)',hint:'4-10+6=0.'},{question:'Remainder when x³+3x-4 is divided by (x-1)?',answer:'0',hint:'f(1)=1+3-4=0.'}]},
  { id:'solving-systems-three-variables', title:'Systems with Three Variables', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['system of equations','three variables','elimination','Gaussian'], summary:'Solve systems of three linear equations using elimination.', intro:'Three equations, three unknowns. Systematically eliminate one variable at a time.', steps:[{title:'Eliminate one variable',body:'Add/subtract pairs of equations to eliminate the first variable. Get two equations in two unknowns.'},{title:'Solve the 2×2 system',body:'Use elimination or substitution.'},{title:'Back-substitute',body:'Plug two known values into original equation to find third.'},{title:'Check all three',body:'Substitute into all three original equations.'}], explanation:'Gaussian elimination is the systematic matrix method. Used in computer graphics and machine learning.', exercises:[{question:'x+y+z=6, x-y+z=2, x+y-z=4. Solve.',answer:'x=2, y=2, z=2',hint:'Add equations pairwise.'},{question:'2x+y=7, y+z=6, x+z=5. Solve.',answer:'x=3, y=1, z=2',hint:'Substitute from third into first.'},{question:'How many solutions if two equations are parallel planes?',answer:'No solution (inconsistent system)',hint:'Parallel planes never intersect.'}]},
  { id:'rational-inequalities', title:'Rational Inequalities', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['rational inequality','sign chart','critical values','domain'], summary:'Solve rational inequalities using sign charts.', intro:'Move everything to one side, find critical values, then test intervals.', steps:[{title:'Move to one side',body:'(x+2)/(x-1)>0.'},{title:'Critical values',body:'Numerator=0: x=-2. Denominator=0: x=1 (excluded).'},{title:'Sign chart',body:'Test each interval: x<-2, -2<x<1, x>1.'},{title:'Solution',body:'x<-2 or x>1 (where expression >0).'}], explanation:'The domain excludes values where the denominator is zero.', exercises:[{question:'(x-3)/(x+2)>0. Solution?',answer:'x<-2 or x>3',hint:'Critical values: -2 and 3.'},{question:'x/(x-4)≤0. Solution?',answer:'0≤x<4',hint:'Critical values: 0 and 4. Test intervals.'},{question:'When is a rational expression negative?',answer:'When numerator and denominator have opposite signs',hint:'Positive/negative = negative.'}]},
  { id:'natural-log', title:'Natural Logarithm Applications', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['natural log','ln','e','continuous growth','half life'], summary:'Apply the natural logarithm to solve exponential growth and decay problems.', intro:'The natural log ln is the inverse of e^x. It appears in continuous growth, decay, and all of calculus.', steps:[{title:'ln and e are inverses',body:'ln(e^x)=x. e^(ln x)=x.'},{title:'Continuous growth',body:'A=Pe^(rt). Continuously compounded $1000 at 5% for 3 years: 1000e^(0.15)≈$1162.'},{title:'Half-life formula',body:'A=A₀e^(kt). Find k: 1/2=e^(k×T₁/₂) → k=ln(0.5)/T₁/₂.'},{title:'Solve with ln',body:'Take ln of both sides to solve exponential equations.'}], explanation:'e^x is its own derivative — this is what makes it so fundamental in calculus.', exercises:[{question:'ln(e⁷)=?',answer:'7',hint:'ln and e cancel.'},{question:'Solve e^(2x)=50.',answer:'x=ln50/2≈1.96',hint:'Take ln: 2x=ln50.'},{question:'$2000 at 6% continuously. Value after 5 years?',answer:'2000e^0.3≈$2699.72',hint:'2000×e^(0.06×5).'}]},
  { id:'applications-of-derivatives', title:'Applications of Derivatives', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['derivative','applications','velocity','acceleration','rate of change'], summary:'Apply derivatives to find velocity, acceleration, and other rates of change.', intro:'The derivative of position is velocity. The derivative of velocity is acceleration.', steps:[{title:'Position function',body:'s(t)=t³-6t²+9t. Position at time t.'},{title:'Velocity v(t)',body:"v(t)=s'(t)=3t²-12t+9."},{title:'Acceleration a(t)',body:"a(t)=v'(t)=6t-12."},{title:'When is particle at rest?',body:'v(t)=0: 3t²-12t+9=0 → t=1 or t=3.'},{title:'Direction of motion',body:'v>0: moving right/up. v<0: moving left/down.'}], explanation:'Derivatives are the mathematical language of physics — Newton used them to describe planetary motion.', exercises:[{question:'s(t)=t²+3t. Find v(t).',answer:'v(t)=2t+3',hint:"Differentiate."},{question:'v(t)=4t-8. When at rest?',answer:'t=2',hint:'4t-8=0.'},{question:'a(t)=6t-4. When is acceleration zero?',answer:'t=2/3',hint:'6t=4.'}]},
  { id:'integration-by-parts', title:'Integration by Parts', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['integration by parts','formula','product','LIATE'], summary:'Evaluate integrals of products using integration by parts.', intro:'Integration by parts is the product rule in reverse: ∫u dv = uv - ∫v du.', steps:[{title:'Choose u and dv',body:'LIATE order for u: Logarithm, Inverse trig, Algebraic, Trigonometric, Exponential.'},{title:'Differentiate u, integrate dv',body:'u=x, dv=e^x dx → du=dx, v=e^x.'},{title:'Apply formula',body:'∫xe^x dx = xe^x - ∫e^x dx = xe^x - e^x + C.'},{title:'Sometimes repeat',body:'∫x²e^x dx: apply parts twice.'}], explanation:'Integration by parts is derived from the product rule for differentiation.', exercises:[{question:'∫x cos x dx=?',answer:'x sin x + cos x + C',hint:'u=x, dv=cosx dx.'},{question:'∫ln x dx=?',answer:'x ln x - x + C',hint:'u=ln x, dv=dx.'},{question:'∫x e^x dx=?',answer:'xe^x - e^x + C',hint:'u=x, dv=e^x dx.'}]},
  { id:'statistics-chi-square', title:'Chi-Square Test', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['chi-square','goodness of fit','independence','categorical','expected observed'], summary:'Apply the chi-square test to categorical data.', intro:'The chi-square test asks: is the difference between observed and expected frequencies due to chance?', steps:[{title:'Observed vs Expected',body:'Compare what you got (observed) to what probability predicts (expected).'},{title:'Chi-square statistic',body:'χ²=Σ(O-E)²/E.'},{title:'Degrees of freedom',body:'df=(rows-1)(cols-1) for independence test.'},{title:'Compare to critical value',body:'If χ²>critical value, reject null hypothesis.'}], explanation:'Chi-square tests are widely used in science to test whether categorical data fits a model.', exercises:[{question:'O={30,20}, E={25,25}. χ²?',answer:'(25/25)+(25/25)=2',hint:'(30-25)²/25+(20-25)²/25=1+1=2.'},{question:'χ²=12, critical value=9.49, α=0.05. Conclusion?',answer:'Reject H₀ — significant difference',hint:'12>9.49.'},{question:'Chi-square uses what type of data?',answer:'Categorical (counts of categories)',hint:'Frequencies, not means.'}]},
  { id:'arc-length-surface-area-calc', title:'Arc Length (Calculus)', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['arc length','integral','curve length','calculus'], summary:'Calculate the length of a curve using the arc length integral formula.', intro:'The arc length of y=f(x) on [a,b] is ∫√(1+(f\'(x))²) dx.', steps:[{title:'Formula',body:'L = ∫ₐᵇ √(1+(dy/dx)²) dx.'},{title:'Find dy/dx',body:'y=x². dy/dx=2x.'},{title:'Plug in',body:'L=∫₀¹√(1+4x²)dx. (Requires substitution or trig sub.)'},{title:'Simple case',body:'y=3x+2 on [0,4]: dy/dx=3. L=∫₀⁴√10 dx=4√10.'}], explanation:'Arc length formula comes from the Pythagorean theorem applied to infinitely small segments.', exercises:[{question:'y=3x on [0,5]. Arc length?',answer:'5√10',hint:'L=5√(1+9)=5√10.'},{question:'y=x on [1,3]. Length?',answer:'2√2',hint:'dy/dx=1. √2×2.'},{question:'Why is arc length always ≥ horizontal distance (b-a)?',answer:'Curves are always at least as long as the straight horizontal span',hint:'√(1+(f\'(x))²)≥1.'}]},
  { id:'generating-functions', title:'Polynomial Functions: Roots and Graphs', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['polynomial','degree','roots','end behavior','turning points'], summary:'Analyze polynomial functions from their degree, leading coefficient, and roots.', intro:'A polynomial\'s graph behavior is determined by its degree and leading coefficient.', steps:[{title:'End behavior',body:'Degree even, leading + : both ends up. Degree even, leading - : both ends down. Degree odd, leading + : down-left, up-right. Leading - : up-left, down-right.'},{title:'Roots from factored form',body:'f(x)=(x-2)²(x+3): zeros at x=2 (touches) and x=-3 (crosses).'},{title:'Multiplicity',body:'Odd multiplicity → crosses x-axis. Even multiplicity → touches (bounces).'}], explanation:'The degree of a polynomial equals the maximum number of roots (real and complex).', exercises:[{question:'f(x)=x³-4x. End behavior?',answer:'Down-left, up-right',hint:'Degree 3, positive leading.'},{question:'f(x)=(x-1)²(x+2). Roots?',answer:'x=1 (touches), x=-2 (crosses)',hint:'Multiplicities 2 and 1.'},{question:'Degree 5 polynomial: max real roots?',answer:'5',hint:'Degree = max roots.'}]},
  { id:'sequences-convergence', title:'Convergence of Sequences and Series', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['convergence','infinite series','geometric series','sum','diverge'], summary:'Determine whether infinite geometric series converge and find their sums.', intro:'An infinite geometric series converges when |r|<1 and its sum is S=a/(1-r).', steps:[{title:'Geometric series',body:'a + ar + ar² + … = a/(1-r) when |r|<1.'},{title:'Test |r|',body:'r=0.5: |0.5|<1 → converges. r=2: |2|>1 → diverges.'},{title:'Find sum',body:'1+0.5+0.25+…: a=1, r=0.5. S=1/(1-0.5)=2.'},{title:'Partial sums',body:'Sₙ=a(1-rⁿ)/(1-r). As n→∞ and |r|<1: Sₙ→a/(1-r).'}], explanation:'Zeno\'s paradoxes (1/2+1/4+1/8+…=1) are resolved by convergent infinite series.', exercises:[{question:'Sum: 1+1/3+1/9+…?',answer:'3/2',hint:'a=1, r=1/3. 1/(2/3)=3/2.'},{question:'Sum: 4+2+1+0.5+…?',answer:'8',hint:'a=4, r=0.5. 4/0.5=8.'},{question:'Sum: 3+4.5+6.75+…?',answer:'Diverges (r=1.5>1)',hint:'|r|>1.'}]},
];